mapper.select:
SELECT COUNT(*)
FROM product_currencies
WHERE product_no = #{productNo}
  AND currency_code = #{currencyCode}

SELECT COUNT(*)
FROM product_rates
WHERE product_no = #{productNo}
  AND rate_no = #{rateNo}
  AND period_month = #{periodMonth}

SELECT terms_title
FROM product_terms
WHERE terms_code = #{termsCode}

SELECT COUNT(*)
FROM id_verifications
WHERE verification_no = #{verificationNo}
  AND user_no = #{userNo}
  AND product_no = #{productNo}
  AND verification_status = '성공'
  AND matched_name_yn = 'Y'
  AND matched_birth_yn = 'Y'
  AND (expired_dt IS NULL OR expired_dt > SYSDATE)
